glsl.fragment:
uniform float time;
uniform float flareBand;
uniform float grain;
uniform float temperature;
varying vec2 vUv;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453123);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);f=f*f*(3.0-2.0*f);float a=hash(i);float b=hash(i+vec2(1.0,0.0));float c=hash(i+vec2(0.0,1.0));float d=hash(i+vec2(1.0,1.0));return mix(mix(a,b,f.x),mix(c,d,f.x),f.y);}
void main(){vec2 uv=vUv;float band=smoothstep(flareBand-0.12,flareBand,uv.y)-smoothstep(flareBand,flareBand+0.14,uv.y);float grit=noise(uv*18.0+time*0.02)*grain;vec3 warm=vec3(0.79,0.42,0.12);vec3 cool=vec3(0.20,0.35,0.52);vec3 col=mix(cool,warm,temperature);col += band*vec3(0.22,0.16,0.08)+grit*0.12;gl_FragColor=vec4(col, clamp(band*0.65+grit*0.3,0.0,0.78));}
